// N/D near MAX_FLOAT_F64
VCC = 0x1LL;
if S0.f64 == S1.f64 then
// Only scale the denominator







D0.f64 = ldexp(S0.f64, 128)
endif
elsif S1.f64 == DENORM.f64 then
